1	import { describe, it, expect } from "vitest";
2	import { quote } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / processing fee
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
8	    expect(quote(customer, [])).toBe(5);
9	  });
10	
11	  // Base premiums for single items (with first insurance + fee, newcomer)
12	  it("quote for a single plain sword (newcomer, no contracts) yields 115 G (100 base + 10 first + 5 fee)", () => {
13	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
14	    const sword = { type: "sword", material: "steel", enchantment: 3, cursed: false };
15	    expect(quote(customer, [sword])).toBe(115);
16	  });
17	  it("quote for a single plain amulet (newcomer) yields 71 G (60 base + 6 first + 5 fee)", () => {
18	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
19	    const amulet = { type: "amulet", material: "silver", enchantment: 2, cursed: false };
20	    expect(quote(customer, [amulet])).toBe(71);
21	  });
22	  it("quote for a single plain staff (newcomer) yields 93 G (80 base + 8 first + 5 fee)", () => {
23	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
24	    const staff = { type: "staff", material: "wood", enchantment: 0, cursed: false };
25	    expect(quote(customer, [staff])).toBe(93);
26	  });
27	  it("quote for a single plain potion (newcomer) yields 49 G (40 base + 4 first + 5 fee)", () => {
28	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
29	    const potion = { type: "potion", material: "glass", enchantment: 0, cursed: false };
30	    expect(quote(customer, [potion])).toBe(49);
31	  });
32	
33	  // Components base premiums
34	  it("quote for 2 runes yields base premium 50 G (no block applies)", () => {
35	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
36	    const rune = { type: "rune" };
37	    expect(quote(customer, [rune, rune])).toBe(60);
38	  });
39	  it("quote for 3 runes yields base premium 60 G (block of 3 alike applies)", () => {
40	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
41	    const rune = { type: "rune" };
42	    expect(quote(customer, [rune, rune, rune])).toBe(71);
43	  });
44	  it("quote for 4 runes yields base premium 100 G (no block — block requires exactly 3)", () => {
45	    const customer = { yearsWithMHPCO: 0, previousContracts: 0 };
46	    const rune = { type: "rune" };
47	    expect(quote(customer, [rune, rune, rune, rune])).toBe(115);
48	  });
49	  it.todo("quote for 7 runes yields base premium 175 G (one block of 3 + 4 individual)");
50	
51	  // "Alike" components — same type
52	  it.todo("quote for 2 runes + 1 moonstone yields base premium 75 G (no block, different types)");
53	  it.todo("quote for 3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");
54	
55	  // Item-specific modifiers
56	  it.todo("cursed sword adds 50% surcharge to that item's base premium");
57	  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
58	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
59	  it.todo("cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");
60	
61	  // Modifier scope on multi-item policies
62	  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base (210 G before policy modifiers + fee)");
63	
64	  // Policy-wide modifiers
65	  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base");
66	  it.todo("first insurance adds 10% surcharge to policy base");
67	  it.todo("follow-up contract gives 15% discount on policy base");
68	
69	  // Processing fee added at the end
70	  it.todo("5 G processing fee is always added after all other modifiers");
71	
72	  // Rounding
73	  it.todo("premium of 197.5 G is rounded UP to 198 G");
74	
75	  // Integration: Newcomer with cursed sword
76	  it.todo("newcomer (0 years, no previous) with cursed sword (steel, ench 3) yields premium 165 G");
77	
78	  // Integration: Long-standing customer's second contract
79	  it.todo("3-year customer's second contract: cursed sword (steel, ench 7) yields premium 160 G");
80	
81	  // CLAIM PROCESSING — basic
82	  it.todo("standard sword damage 500 G yields payout 400 G (500 - 100 deductible)");
83	  it.todo("rune damage 200 G yields payout 100 G (200 - 100 deductible, no special clauses)");
84	
85	  // Claim payout rounding
86	  it.todo("payout of 350.5 G is rounded DOWN to 350 G");
87	
88	  // Deductible per damage event
89	  it.todo("dragon attack damages sword (500) and amulet (300): payout 600 G (deductible applies once per item)");
90	
91	  // Special reimbursement clauses
92	  it.todo("steel sword with enchantment 9, damage 1000 G: payout 400 G (50% then deductible)");
93	  it.todo("dragon-material sword with enchantment 5, damage 800 G: payout 700 G (full reimbursement then deductible)");
94	  it.todo("dragon-material sword with enchantment 9, damage 1000 G: payout 400 G (50% wins, then deductible)");
95	  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies)");
96	
97	  // Cap
98	  it.todo("sword policy (sum 1000, cap 2000): two claims of 1500 each yield first payout 1400 G with cap 600 remaining");
99	  it.todo("sword policy second claim of 1500 G with 600 G cap remaining yields payout 600 G and cap 0");
100	  it.todo("cursed sword: cap is 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
101	  it.todo("policy with sword + 3 runes: insurance sum 1750 G (block discount affects only premium, not insurance sum)");
102	
103	  // Multiple items of same type
104	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
105	  it.todo("two sword damage entries each get their own deductible when both swords are insured");
106	  it.todo("two sword damage entries when only one sword is insured: claim is rejected");
107	
108	  // Error cases
109	  it.todo("quote with unknown item type (e.g. broomstick): exits non-zero with stderr message");
110	  it.todo("claim referencing item not in policy: exits non-zero with stderr message");
111	  it.todo("claim with negative damage amount: exits non-zero with stderr message");
112	
113	  // CLI integration
114	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout");
115	  it.todo("CLI processes sequential steps; claim refers to earlier quote by zero-based step index");
116	});
