1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	};
9	
10	const PROCESSING_FEE = 5;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	const BLOCK_SIZE = 3;
23	const BLOCK_PREMIUM = 60;
24	
25	export function quote(customer: Customer, items: Item[]): number {
26	  const countsByType: Record<string, number> = {};
27	  for (const item of items) {
28	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
29	  }
30	
31	  let policyBase = 0;
32	  for (const type of Object.keys(countsByType)) {
33	    const count = countsByType[type];
34	    const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
35	    policyBase += isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
36	  }
37	
38	  return Math.ceil((policyBase * 11) / 10) + PROCESSING_FEE;
39	}
